mapper.select:
select * from `course`

     and id = #{id}

order by id desc

mapper.update:
update `course`
course_name = #{courseName}, course_code = #{courseCode}, teacher_id = #{teacherId}, credit = #{credit}, semester = #{semester}, total_weeks = #{totalWeeks}, attendance_required_count = #{attendanceRequiredCount}, exam_qualification_rate = #{examQualificationRate}, description = #{description}, create_time = #{createTime}, update_time = #{updateTime},
where id = #{id}
